__global__ void Fan1(float *data_11,
                     float *val_10,
                     float *item_4,
                     const int data_2,
                     const int t) {
    int item_5 = blockIdx.x * blockDim.x + threadIdx.x;

    if (data_2 - 1 - t > item_5) {
        data_11[data_2 * (item_5 + t + 1) + t] = val_10[data_2 * (item_5 + t + 1) + t] / val_10[data_2 * t + t];
    }
}

__global__ void Fan2(float *elem_9,
                     float *elem_0,
                     float *item_1,
                     const int item_7,
                     const int t) {
    int x_6 = blockIdx.x * blockDim.x + threadIdx.x;
    int x_8 = blockIdx.y * blockDim.y + threadIdx.y;

    if (item_7 - 1 - t > x_6 && item_7 - t > x_8) {
        elem_0[item_7 * (x_6 + 1 + t) + (x_8 + t)] -= elem_9[item_7 * (x_6 + 1 + t) + t] * elem_0[item_7 * t + (x_8 + t)];

        if (0 == x_8) {
            item_1[x_6 + 1 + t] -= elem_9[item_7 * (x_6 + 1 + t) + (x_8 + t)] * item_1[t];
        }
    }
}

void InitPerRun(int size, float *m) {
    for (int i = 0; i < size * size; i++) {
        m[i] = 0.0f;
    }
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    for (int i = 0; i < size; i++) {
        finalVec[size - i - 1] = b[size - i - 1];
        for (int j = 0; j < i; j++) {
            finalVec[size - i - 1] -= a[size * (size - i - 1) + (size - j - 1)] * finalVec[size - j - 1];
        }
        finalVec[size - i - 1] /= a[size * (size - i - 1) + (size - i - 1)];
    }
}

void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    for (int i = 0; i < nrow; i++) {
        for (int j = 0; j < ncol; j++) {
            fscanf(fp, "%f", ary + size * i + j);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    for (int i = 0; i < ary_size; i++) {
        fscanf(fp, "%f", &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    for (int i = 0; i < nrow; i++) {
        for (int j = 0; j < ncol; j++) {
            printf("%8.2f ", ary[size * i + j]);
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    for (int i = 0; i < ary_size; i++) {
        printf("%.2f ", ary[i]);
    }
    printf("\n");
}

int main() {
    int Size;
    char filename[30];
    printf("Enter the data file name: ");
    scanf("%s", filename);
    printf("The file name is: %s\n", filename);

    FILE *fp = fopen(filename, "r");
    if (!fp) {
        printf("Failed to open file %s\n", filename);
        return -1;
    }

    fscanf(fp, "%d", &Size);

    float *a = (float *)malloc(Size * Size * sizeof(float));
    InitMat(fp, Size, a, Size, Size);
    printf("The input matrix a is:\n");
    PrintMat(a, Size, Size, Size);

    float *b = (float *)malloc(Size * sizeof(float));
    InitAry(fp, b, Size);
    printf("The input array b is:\n");
    PrintAry(b, Size);

    fclose(fp);

    float *m = (float *)malloc(Size * Size * sizeof(float));
    InitPerRun(Size, m);

    // Allocate device memory
    float *d_a, *d_b, *d_m;
    cudaError_t err;
    err = cudaMalloc((void **)&d_a, Size * Size * sizeof(float));
    if (err != cudaSuccess) { printf("cudaMalloc d_a failed\n"); return -1; }
    err = cudaMalloc((void **)&d_b, Size * sizeof(float));
    if (err != cudaSuccess) { printf("cudaMalloc d_b failed\n"); return -1; }
    err = cudaMalloc((void **)&d_m, Size * Size * sizeof(float));
    if (err != cudaSuccess) { printf("cudaMalloc d_m failed\n"); return -1; }

    // Copy data to device
    err = cudaMemcpy(d_a, a, Size * Size * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { printf("cudaMemcpy d_a failed\n"); return -1; }
    err = cudaMemcpy(d_b, b, Size * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { printf("cudaMemcpy d_b failed\n"); return -1; }
    err = cudaMemcpy(d_m, m, Size * Size * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { printf("cudaMemcpy d_m failed\n"); return -1; }

    for (int t = 0; t < Size - 1; t++) {
        // Launch Fan1 kernel
        int fan1_grid = (Size + BLOCK_SIZE_0 - 1) / BLOCK_SIZE_0;
        Fan1<<<fan1_grid, BLOCK_SIZE_0>>>(d_m, d_a, d_b, Size, t);
        cudaDeviceSynchronize();

        // Launch Fan2 kernel
        dim3 fan2_grid((Size + BLOCK_SIZE_1_X - 1) / BLOCK_SIZE_1_X, (Size + BLOCK_SIZE_1_Y - 1) / BLOCK_SIZE_1_Y);
        dim3 fan2_block(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y);
        Fan2<<<fan2_grid, fan2_block>>>(d_m, d_a, d_b, Size, t);
        cudaDeviceSynchronize();
    }

    // Copy results back to host
    err = cudaMemcpy(a, d_a, Size * Size * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) { printf("cudaMemcpy a failed\n"); return -1; }
    err = cudaMemcpy(b, d_b, Size * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) { printf("cudaMemcpy b failed\n"); return -1; }
    err = cudaMemcpy(m, d_m, Size * Size * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) { printf("cudaMemcpy m failed\n"); return -1; }

    printf("The result of matrix m is: \n");
    PrintMat(m, Size, Size, Size);
    printf("The result of matrix a is: \n");
    PrintMat(a, Size, Size, Size);
    printf("The result of array b is: \n");
    PrintAry(b, Size);

    float *finalVec = (float *)malloc(Size * sizeof(float));
    BackSub(a, b, finalVec, Size);
    printf("The final solution is: \n");
    PrintAry(finalVec, Size);

    // Free device memory
    cudaFree(d_a);
    cudaFree(d_b);
    cudaFree(d_m);

    free(a);
    free(b);
    free(m);
    free(finalVec);

    return 0;
}
